mapper.select:
SELECT ELE_ID, PLAYLIST_ID, SONG_ID
FROM PLAYLIST_ELE_TBL
WHERE PLAYLIST_ID = #{playListId}

SELECT PLAYLIST_ID, TITLE
FROM PLAYLISTS_TBL
WHERE USER_ID = #{userId}

SELECT CASE
    WHEN EXISTS (
        SELECT 1
        FROM PLAYLISTS_TBL
        WHERE USER_ID = #{userId}
        AND TITLE = #{title}
    )
    THEN 1 ELSE 0
    END result
FROM dual

SELECT *
FROM PLAYLISTS_TBL
WHERE USER_ID = #{userId}
AND LIST_TYPE = #{listType}
